      "find_all_primes_1_100_using_the_sieve_": "Trouver tous les nombres premiers de 1 à 100 avec le crible d'Ératosthène.",
      "fluently_decompose_any_number_from_5_t": "Décomposer avec aisance tout nombre de 5 à 10.",
      "build_mental_imagery_of_place_value_vi": "Se construire une image mentale de la valeur de position via le boulier.",
      "connect_the_standard_addition_algorith": "Relier l'algorithme standard de l'addition au regroupement physique.",
      "subitize_numbers_1_6_instantly": "Subitiser les nombres 1-6 instantanément.",
      "use_counters_as_a_thermometer_model": "Utiliser les jetons comme modèle de thermomètre.",
      "build_symmetric_designs": "Construire des motifs symétriques.",
      "notice_that_adds_10_and_adds_1": "Remarquer que ↓ ajoute 10 et → ajoute 1.",
      "find_all_trains_of_a_given_total": "Trouver tous les « trains » d'un total donné.",
      "sort_quadrilaterals_by_their_propertie": "Trier les quadrilatères selon leurs propriétés.",
      "master_the_doubles_facts_1_1_2_2_3_3_5": "Maîtriser les faits de doubles (1+1, 2+2, 3+3, ..., 5+5).",
      "estimate_before_computing": "Estimer avant de calculer.",
